   106→/**
   107→ * AI Routing Stage Implementation
   108→ *
   109→ * Analyzes classification confidence and determines optimal routing strategy
   110→ * for email processing continuation.
   111→ *
   112→ * CANONICAL SIGNATURE: (email, session, result, config) => void
   113→ * Mutates result.needsAiClassification and adds explainability trace
   114→ */
   115→export function aiRoutingStage(
   116→  email: EmailMessage,
   117→  session: ClassificationSession,
   118→  result: ClassificationResult,
   119→  config: AIRoutingConfig
   120→): void {
   121→  const startTime = Date.now();
   122→
   123→  // Validate inputs
   124→  validateInputs(email, session, result, config);
   125→
   126→  // Extract data from result object
   127→  const selectedLabels = result.selectedLabels;
   128→  const candidateScores = result.candidateScores;
   129→
   130→  // Extract routing thresholds from config.settings.aiRouting (these are on 0-1 normalized scale)
   131→  // NOTE: config.confidenceThresholds.* are ABSOLUTE SCORES (0-15+ scale) from rule scoring - DO NOT USE HERE
   132→  const highConfidenceThreshold = config.settings.aiRouting.highConfidenceThreshold || 0.8;
   133→
   134→  const aiRequiredThreshold = config.settings.aiRouting.aiRequiredThreshold || 0.5;
   135→
   136→  // lowConfidenceThreshold not currently in config, use sensible default
   137→  const lowConfidenceThreshold = 0.3;
   138→
   139→  const skipAiConditions = config.settings.aiRouting.skipAiConditions || [];
   140→
   141→  // Make routing decision
   142→  const routingDecision = makeRoutingDecision(
   143→    selectedLabels,
   144→    candidateScores,
   145→    result, // Pass result for normalized confidence value
   146→    highConfidenceThreshold,
   147→    aiRequiredThreshold,
   148→    lowConfidenceThreshold,
   149→    skipAiConditions
   150→  );
