   152→  // Generate explainability trace
   153→  const explainabilityTrace = generateExplainabilityTrace(
   154→    selectedLabels,
   155→    candidateScores,
   156→    routingDecision,
   157→    {
   158→      highConfidenceThreshold: highConfidenceThreshold,
   159→      aiRequiredThreshold: aiRequiredThreshold,
   160→      lowConfidenceThreshold: lowConfidenceThreshold,
   161→    },
   162→    startTime
   163→  );
   164→
   165→  // Mutate result in place
   166→  result.needsAiClassification = routingDecision.routeToAi;
   167→  result.aiRoutingUsed = routingDecision.routeToAi; // Also update aiRoutingUsed for backward compatibility
   168→
   169→  // Initialize explainabilityTrace if not exists (defensive check)
   170→  if (!result.explainabilityTrace) {
   171→    throw new Error('CRITICAL: explainabilityTrace is not initialized in result object');
   172→  }
   173→
   174→  // Add explainability trace to result - store in appropriate field
   175→  if (!result.explainabilityTrace.aiRouting) {
   176→    result.explainabilityTrace.aiRouting = {
   177→      routingDecision: routingDecision.routeToAi ? 'fullClassification' : 'skipAi',
   178→      highConfidenceThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.highConfidenceThreshold,
   179→      aiRequiredThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.aiRequiredThreshold,
   180→      skipConditions: [],
   181→      reason: routingDecision.routingReason,
   182→    };
   183→  }
   184→
   185→  // Track processing time
   186→  result.explainabilityTrace.stageTimings = result.explainabilityTrace.stageTimings || {};
   187→  result.explainabilityTrace.stageTimings['aiRouting'] = explainabilityTrace.processingMetadata.processingTimeMs;
   188→}
