   190→/**
   191→ * Validate input parameters
   192→ */
   193→function validateInputs(
   194→  email: EmailMessage,
   195→  session: ClassificationSession,
   196→  result: ClassificationResult,
   197→  config: AIRoutingConfig
   198→): void {
   199→  validateEmailInput(email);
   200→  validateSessionInput(session);
   201→  validateConfigInput(config);
   202→
   203→  if (!result) {
   204→    throw new Error('Classification result is required');
   205→  }
   206→
   207→  if (!result.selectedLabels) {
   208→    throw new Error('Selected labels are required in result');
   209→  }
   210→
   211→  if (!result.candidateScores) {
   212→    throw new Error('Candidate scores are required in result');
   213→  }
   214→
   215→  // Validate confidence scores
   216→  for (const label of result.selectedLabels) {
   217→    validateConfidenceScore(label.confidence);
   218→  }
   219→}
