   221→/**
   222→ * Core routing decision logic
   223→ *
   224→ * Implements the three-threshold AI routing strategy:
   225→ * - High confidence (>= highThreshold): Skip AI - rule-based results are reliable
   226→ * - Low confidence (< lowThreshold): Skip AI - too uncertain for AI to help
   227→ * - Medium confidence (lowThreshold <= score < highThreshold):
   228→ *   - If score >= aiRequiredThreshold: Route to AI (worth the cost)
   229→ *   - Otherwise: Skip AI (below cost threshold)
   230→ *
   231→ * @param selectedLabels - Labels selected by multi-label selection stage
   232→ * @param candidateScores - All candidate category scores
   233→ * @param result - Classification result with normalized confidence (0-1 scale)
   234→ * @param highConfidenceThreshold - Skip AI if score >= this (confident in rules)
   235→ * @param aiRequiredThreshold - Within medium range, route to AI if score >= this
   236→ * @param lowConfidenceThreshold - Skip AI if score < this (too uncertain)
   237→ * @param skipAiConditions - Additional conditions to skip AI (e.g., hardAssertion)
   238→ * @returns Routing decision with reasoning
   239→ */
   240→function makeRoutingDecision(
   241→  selectedLabels: SelectedLabel[],
   242→  candidateScores: Record<string, CandidateScore>,
   243→  result: ClassificationResult,
   244→  highConfidenceThreshold: number,
   245→  aiRequiredThreshold: number,
   246→  lowConfidenceThreshold: number,
   247→  skipAiConditions: string[]
   248→): RoutingDecision {
   249→  // Case 1: No labels selected - route to AI for last chance classification
   250→  if (selectedLabels.length === 0) {
   251→    return {
   252→      routeToAi: true,
   253→      routingReason:
   254→        'No labels selected due to insufficient confidence in rule-based classification - AI may recover classification',
   255→      confidenceAssessment: 'noClassification',
   256→      costConsideration: 'recoveryAttempt',
   257→    };
   258→  }
   259→
   260→  // Case 2: Check for hard assertions (skip AI condition)
   261→  // Hard assertions are domain-based classifications that are authoritative
   262→  if (skipAiConditions.includes('hardAssertion')) {
   263→    const hasHardAssertion = Object.values(candidateScores).some((score) => score.hardAssertion);
   264→    if (hasHardAssertion) {
   265→      return {
   266→        routeToAi: false,
   267→        routingReason: 'hard assertion applied - domain-based classification is authoritative',
   268→        confidenceAssessment: 'hardAssertionSkip',
   269→        costConsideration: 'aiUnnecessary',
   270→      };
   271→    }
   272→  }
   273→
   274→  // Case 3: Analyze primary label confidence for threshold-based routing
   275→  // NOTE: Use result.confidence (normalized 0-1 scale) not selectedLabels[].confidence (0-100 scale)
   276→  const primaryLabel = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
   277→
   278→  // Get normalized confidence from result (set by multi-label selection)
   279→  // If not set, this is an error - we should always have confidence by now
   280→  if (result.confidence === undefined || result.confidence === null) {
   281→    throw new Error('CRITICAL: result.confidence not set by multi-label selection stage');
   282→  }
   283→  const primaryScore = result.confidence; // Normalized to 0-1 scale by multi-label selection
   284→
   285→  // High confidence threshold check: score >= highThreshold → Skip AI
   286→  // Rule-based results are reliable at this confidence level
   287→  if (primaryScore >= highConfidenceThreshold) {
   288→    return {
   289→      routeToAi: false,
   290→      routingReason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
   291→      confidenceAssessment: 'highConfidence',
   292→      costConsideration: 'aiUnnecessary',
   293→    };
   294→  }
   295→
   296→  // Low confidence threshold check: score < lowThreshold → Skip AI
   297→  // Too uncertain for AI to provide meaningful improvement
   298→  if (primaryScore < lowConfidenceThreshold) {
   299→    return {
   300→      routeToAi: false,
   301→      routingReason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
   302→      confidenceAssessment: 'veryLowConfidence',
   303→      costConsideration: 'aiIneffective',
   304→    };
   305→  }
   306→
   307→  // Medium confidence range: lowThreshold <= score < highThreshold
   308→  // Analyze additional factors to determine if AI is worth the cost
   309→  const hasMultipleLabels = selectedLabels.length > 1;
   310→  const hasCloseCompetitors = checkCloseCompetitors(candidateScores, primaryScore, 3);
   311→
   312→  // Build routing reason with contextual factors
   313→  if (primaryScore >= lowConfidenceThreshold && primaryScore < highConfidenceThreshold) {
   314→    let aiRoutingReason = `Medium confidence primary label ${primaryLabel.category} (score: ${primaryScore})`;
   315→    let costConsideration = 'beneficialEnhancement';
   316→
   317→    // Additional factors that increase AI value
   318→    if (hasCloseCompetitors) {
   319→      aiRoutingReason += ' with close competing categories';
   320→      costConsideration = 'disambiguationValuable';
   321→    }
   322→
   323→    if (hasMultipleLabels) {
   324→      aiRoutingReason += ' with multiple labels selected';
   325→      costConsideration = 'multiLabelValidation';
   326→    }
   327→
   328→    // Apply aiRequiredThreshold: only route to AI if score is high enough
   329→    // This prevents routing low-medium confidence emails that won't benefit from AI
   330→    if (primaryScore >= aiRequiredThreshold) {
   331→      return {
   332→        routeToAi: true,
   333→        routingReason:
   334→          aiRoutingReason + ' - insufficient confidence in rule-based classification, AI can improve accuracy',
   335→        confidenceAssessment: 'mediumConfidence',
   336→        costConsideration: costConsideration,
   337→      };
   338→    } else {
   339→      return {
   340→        routeToAi: false,
   341→        routingReason:
   342→          aiRoutingReason +
   343→          ' but below AI routing threshold - accept rule-based result despite insufficient confidence',
   344→        confidenceAssessment: 'lowMediumConfidence',
   345→        costConsideration: 'costThresholdNotMet',
   346→      };
   347→    }
   348→  }
   349→
   350→  // Default case (shouldn't reach here with proper threshold ordering: low < aiRequired < high)
   351→  return {
   352→    routeToAi: false,
   353→    routingReason: `Unclear confidence assessment (score: ${primaryScore}) - defaulting to rule-based results`,
   354→    confidenceAssessment: 'unclear',
   355→    costConsideration: 'defaultConservative',
   356→  };
   357→}
   358→
   359→/**
   360→ * Check if there are close competing categories that AI could help disambiguate
   361→ */
   362→function checkCloseCompetitors(
   363→  candidateScores: Record<string, CandidateScore>,
   364→  primaryScore: number,
   365→  competitorGap: number = 3
   366→): boolean {
   367→  const competitors = Object.entries(candidateScores)
   368→    .map(([categoryCode, scoreData]) => ({
   369→      category: categoryCode,
   370→      score: scoreData.score || 0,
   371→    }))
   372→    .filter((cat) => cat.score > 0 && cat.score < primaryScore)
   373→    .filter((cat) => primaryScore - cat.score <= competitorGap);
   374→
   375→  return competitors.length > 0;
   376→}
   377→
   378→/**
   379→ * Generate comprehensive explainability trace
   380→ */
   381→function generateExplainabilityTrace(
   382→  selectedLabels: SelectedLabel[],
   383→  candidateScores: Record<string, CandidateScore>,
   384→  routingDecision: RoutingDecision,
   385→  thresholds: {
   386→    highConfidenceThreshold: number;
   387→    aiRequiredThreshold: number;
   388→    lowConfidenceThreshold: number;
   389→  },
   390→  startTime: number
   391→): AIRoutingExplainabilityTrace {
   392→  const processingTime = Date.now() - startTime;
   393→  const primaryLabel = selectedLabels.find((l) => l.isPrimary) || selectedLabels[0];
   394→
   395→  return {
   396→    stageType: 'aiRouting',
   397→    stageOrder: 8,
   398→    decisionFactors: {
   399→      primaryScore: primaryLabel?.confidence || 0,
   400→      thresholdAnalysis: {
   401→        highConfidenceThreshold: thresholds.highConfidenceThreshold,
   402→        aiRequiredThreshold: thresholds.aiRequiredThreshold,
   403→        lowConfidenceThreshold: thresholds.lowConfidenceThreshold,
   404→        primaryScore: primaryLabel?.confidence || 0,
   405→        thresholdMet: primaryLabel?.confidence >= thresholds.aiRequiredThreshold ? 'aiRequired' : 'belowThreshold',
   406→      },
   407→      competitorAnalysis: {
   408→        closeCompetitorsFound: checkCloseCompetitors(candidateScores, primaryLabel?.confidence || 0),
   409→        competitorCount: Object.keys(candidateScores).length - 1,
   410→        multipleLabelsSelected: selectedLabels.length > 1,
   411→      },
   412→    },
   413→    reasoning: routingDecision.routingReason,
   414→    processingMetadata: {
   415→      processingTimeMs: processingTime,
   416→      inputLabelsCount: selectedLabels.length,
   417→      candidateScoresCount: Object.keys(candidateScores).length,
   418→    },
   419→  };
   420→}
